    @pytest.mark.django_db
    def test_potential_attributes_first_view_with_therapies(self, patient_info):
        trial = TrialFactory(
            therapies_required=['vrd'], therapies_excluded=['car_t'],
            therapy_components_excluded=['daratumumab'],
            therapy_types_required=['immunomodulatory_drug_(imid)'],
        )
        pi = patient_info
        pi.prior_therapy = 'More than two lines of therapy'
        pi.first_line_therapy = 'vrd'
        pi.second_line_therapy = 'car_t'
        pi.later_therapy = 'dara_vrd'
        pi.later_therapies = [{'therapy': 'dara_vrd'}]
        pi.later_outcome = 'SD'
        pi.save()

        pi.refresh_from_db()

        assert pi.treatment_refractory_status == 'primaryRefractory'

        res = TrialTemplates(trial, patient_info=patient_info).potential_attributes_first_view(None)
