    @pytest.mark.django_db
    def test_potential_attributes_first_view_having_ulns(self, patient_info):
        t1 = TrialFactory(liver_enzyme_level_alt_uln_min=1.5, liver_enzyme_level_alt_uln_max=2.0)
        t2 = TrialFactory(liver_enzyme_level_alt_uln_min=1.5, liver_enzyme_level_alt_uln_max=None)
